import { useState } from 'react';import { useQuery } from '@tanstack/react-query';import { Link,useParams,useSearchParams } from 'react-router-dom';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { usePermissions } from '@/hooks/usePermissions';import { apiErrorMessage } from '@/lib/apiClient';import { vendorApi } from '../api/vendorApi';import { useCreateRating,useSaveContact,useSaveContract,useSaveQuotation,useSaveSupplier,useSupplier,useSupplierPerformance,useVendorCategories } from '../api/useVendors';import { ContactForm } from '../components/ContactForm';import { ContactTable } from '../components/ContactTable';import { ContractForm } from '../components/ContractForm';import { ContractTimeline } from '../components/ContractTimeline';import { PerformanceCards } from '../components/PerformanceCards';import { QuotationForm } from '../components/QuotationForm';import { QuotationTable } from '../components/QuotationTable';import { RatingForm } from '../components/RatingForm';import { SupplierForm } from '../components/SupplierForm';import { SupplierStatusBadge } from '../components/SupplierStatusBadge';import { VendorModal } from '../components/VendorModal';import { VendorPageSkeleton } from '../components/VendorPageSkeleton';import type { ContactFormValues,ContractFormValues,QuotationFormValues,RatingFormValues,SupplierFormValues } from '../types';
const tabs=['overview','contacts','contracts','quotations','purchasing'] as const;
export const SupplierDetailsPage=()=>{const id=Number(useParams().id||0);const [sp,setSp]=useSearchParams();const tab=(sp.get('tab')||'overview') as typeof tabs[number];const [modal,setModal]=useState<'supplier'|'contact'|'contract'|'quotation'|'rating'|null>(null);const {can}=usePermissions();const supplier=useSupplier(id);const categories=useVendorCategories();const performance=useSupplierPerformance(id);const contacts=useQuery({queryKey:['vendors',id,'contacts'],queryFn:()=>vendorApi.supplierContacts(id),enabled:id>0});const contracts=useQuery({queryKey:['vendors',id,'contracts'],queryFn:()=>vendorApi.supplierContracts(id),enabled:id>0});const quotations=useQuery({queryKey:['vendors',id,'quotations'],queryFn:()=>vendorApi.supplierQuotations(id),enabled:id>0});const ratings=useQuery({queryKey:['vendors',id,'ratings'],queryFn:()=>vendorApi.ratings(id),enabled:id>0});const orders=useQuery({queryKey:['vendors',id,'purchase-orders'],queryFn:()=>vendorApi.purchaseOrders(id),enabled:id>0});const products=useQuery({queryKey:['vendors',id,'products'],queryFn:()=>vendorApi.products(id),enabled:id>0});const finance=useQuery({queryKey:['vendors',id,'finance'],queryFn:()=>vendorApi.financialReferences(id),enabled:id>0});const saveSupplier=useSaveSupplier(id);const saveContact=useSaveContact(id);const saveContract=useSaveContract(id);const saveQuotation=useSaveQuotation(id);const saveRating=useCreateRating(id);if(supplier.isLoading)return <VendorPageSkeleton/>;if(supplier.error||!supplier.data)return <Alert variant="danger" title="Supplier unavailable">{apiErrorMessage(supplier.error,'Supplier was not found.')}</Alert>;const s=supplier.data;const close=()=>setModal(null);const run=async<T,>(promise:Promise<T>)=>{await promise;close();};const anyError=contacts.error||contracts.error||quotations.error||performance.error||orders.error||products.error||finance.error;return <div className="space-y-6 text-slate-800 dark:text-slate-100"><Link to="/vendors/suppliers" className="text-sm font-semibold text-indigo-600">← Back to suppliers</Link><header className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-slate-700 dark:bg-slate-900"><div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between"><div><div className="flex flex-wrap items-center gap-3"><p className="font-mono text-sm font-bold text-indigo-600">{s.supplier_code}</p><SupplierStatusBadge status={s.status}/></div><h1 className="mt-2 text-3xl font-bold">{s.company_name}</h1><p className="mt-2 text-sm text-slate-500">{[s.city,s.country].filter(Boolean).join(', ')||'Location not provided'} · {s.contact_person||'No primary contact'}</p><div className="mt-3 flex flex-wrap gap-2">{s.categories?.map(c=><span key={c.id} className="rounded-full bg-slate-100 px-3 py-1 text-xs dark:bg-slate-800">{c.name}</span>)}</div></div><div className="flex flex-wrap gap-2">{can('vendors.update')&&s.status!=='archived'?<Button variant="secondary" onClick={()=>setModal('supplier')}>Edit Supplier</Button>:null}{can('vendors.create')?<Button onClick={()=>setModal('contact')}>Add Contact</Button>:null}</div></div><div className="mt-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-4"><Mini label="Purchase Orders" value={s.purchase_order_count}/><Mini label="Contracts" value={s.contract_count}/><Mini label="Quotations" value={s.quotation_count}/><Mini label="Rating" value={s.overall_rating===null?'—':`${Number(s.overall_rating).toFixed(2)} / 5`}/></div></header><nav className="flex overflow-x-auto border-b border-slate-200 dark:border-slate-700">{tabs.map(x=><button key={x} onClick={()=>setSp({tab:x})} className={`whitespace-nowrap border-b-2 px-4 py-3 text-sm font-semibold capitalize ${tab===x?'border-indigo-600 text-indigo-600':'border-transparent text-slate-500'}`}>{x}</button>)}</nav>{anyError?<Alert variant="danger" title="Some supplier information could not be loaded">{apiErrorMessage(anyError)}</Alert>:null}{tab==='overview'?<div className="space-y-6"><section><div className="mb-3 flex items-center justify-between"><h2 className="text-lg font-bold">Supplier Performance</h2>{can('vendors.manage')?<Button size="sm" onClick={()=>setModal('rating')}>Create Review</Button>:null}</div>{performance.data?<PerformanceCards data={performance.data}/>:<div className="h-40 animate-pulse rounded-xl bg-slate-100"/>}</section><div className="grid gap-6 lg:grid-cols-2"><Info title="Company & Tax" rows={[['Tax Number',s.tax_number],['Registration',s.registration_number],['Website',s.website],['Currency',s.currency],['Payment Terms',s.payment_terms]]}/><Info title="Contact & Address" rows={[['Contact',s.contact_person],['Email',s.email],['Phone',s.phone],['Address',s.address],['City / Country',[s.city,s.country].filter(Boolean).join(', ')]]}/></div><section className="rounded-xl border bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><h2 className="font-bold">Rating History</h2><div className="mt-3 space-y-2">{ratings.data?.length?ratings.data.map(r=><div key={r.id} className="flex flex-wrap items-center justify-between rounded-lg bg-slate-50 p-3 text-sm dark:bg-slate-800"><span>{r.review_period_start} → {r.review_period_end}</span><span>Quality {Number(r.product_quality_score).toFixed(1)} / 5</span><strong>Overall {Number(r.overall_rating).toFixed(2)} / 5</strong></div>):<p className="text-sm text-slate-500">No performance reviews yet.</p>}</div></section></div>:null}{tab==='contacts'?<section className="overflow-hidden rounded-xl border bg-white dark:border-slate-700 dark:bg-slate-900"><div className="flex items-center justify-between border-b p-4 dark:border-slate-700"><h2 className="font-bold">Contacts</h2>{can('vendors.create')?<Button size="sm" onClick={()=>setModal('contact')}>Add Contact</Button>:null}</div><ContactTable contacts={contacts.data?.data.map(x=>x.attributes)??[]} isLoading={contacts.isLoading} showSupplier={false}/></section>:null}{tab==='contracts'?<section className="rounded-xl border bg-slate-50 p-6 dark:border-slate-700 dark:bg-slate-950"><div className="mb-5 flex items-center justify-between"><h2 className="font-bold">Contract Timeline</h2>{can('vendors.contracts')?<Button size="sm" onClick={()=>setModal('contract')}>Add Contract</Button>:null}</div><ContractTimeline contracts={contracts.data?.data.map(x=>x.attributes)??[]}/></section>:null}{tab==='quotations'?<section className="overflow-hidden rounded-xl border bg-white dark:border-slate-700 dark:bg-slate-900"><div className="flex items-center justify-between border-b p-4 dark:border-slate-700"><h2 className="font-bold">Quotation History</h2>{can('vendors.create')?<Button size="sm" onClick={()=>setModal('quotation')}>Add Quotation</Button>:null}</div><QuotationTable quotations={quotations.data?.data.map(x=>x.attributes)??[]} isLoading={quotations.isLoading} showSupplier={false}/></section>:null}{tab==='purchasing'?<div className="space-y-6"><ReferenceTable title="Purchase Orders" headers={['PO #','Status','Date','Total']} rows={(orders.data??[]).map(x=>[x.po_number,x.status,x.order_date,`${x.currency} ${Number(x.total_amount).toLocaleString()}`])}/><ReferenceTable title="Inventory Products" headers={['SKU','Product','Vendor SKU','Last Cost']} rows={(products.data??[]).map(x=>[x.sku,x.name,x.vendor_sku||'—',x.last_purchase_cost?`${s.currency} ${Number(x.last_purchase_cost).toLocaleString()}`:'—'])}/><ReferenceTable title="Financial References" headers={['Invoice','Status','Date','Total']} rows={(finance.data?.invoices??[]).map(x=>[x.invoice_number,x.status,x.invoice_date,`${x.currency} ${Number(x.total_amount).toLocaleString()}`])}/></div>:null}{modal==='supplier'?<VendorModal title="Edit Supplier" onClose={close} wide><SupplierForm supplier={s} categories={categories.data??[]} onSubmit={(v:SupplierFormValues)=>void run(saveSupplier.mutateAsync(v))} onCancel={close} isLoading={saveSupplier.isPending} error={saveSupplier.error?apiErrorMessage(saveSupplier.error):null}/></VendorModal>:null}{modal==='contact'?<VendorModal title="Add Contact" onClose={close}><ContactForm onSubmit={(v:ContactFormValues)=>void run(saveContact.mutateAsync(v))} onCancel={close} isLoading={saveContact.isPending}/></VendorModal>:null}{modal==='contract'?<VendorModal title="Add Contract" onClose={close}><ContractForm currency={s.currency} onSubmit={(v:ContractFormValues)=>void run(saveContract.mutateAsync(v))} onCancel={close} isLoading={saveContract.isPending}/></VendorModal>:null}{modal==='quotation'?<VendorModal title="Add Quotation" onClose={close} wide><QuotationForm currency={s.currency} onSubmit={(v:QuotationFormValues)=>void run(saveQuotation.mutateAsync(v))} onCancel={close} isLoading={saveQuotation.isPending}/></VendorModal>:null}{modal==='rating'?<VendorModal title="Create Performance Review" onClose={close}><RatingForm currency={s.currency} onSubmit={(v:RatingFormValues)=>void run(saveRating.mutateAsync(v))} onCancel={close} isLoading={saveRating.isPending}/></VendorModal>:null}</div>;};
const Mini=({label,value}:{label:string;value:string|number|undefined})=><div className="rounded-xl bg-slate-50 p-4 dark:bg-slate-800"><p className="text-xs uppercase tracking-wide text-slate-400">{label}</p><p className="mt-1 text-xl font-bold">{value??0}</p></div>;
const Info=({title,rows}:{title:string;rows:Array<[string,string|null|undefined]>})=><section className="rounded-xl border bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><h2 className="font-bold">{title}</h2><dl className="mt-4 space-y-3">{rows.map(([k,v])=><div key={k} className="flex justify-between gap-4 text-sm"><dt className="text-slate-500">{k}</dt><dd className="text-right font-medium">{v||'—'}</dd></div>)}</dl></section>;
const ReferenceTable=({title,headers,rows}:{title:string;headers:string[];rows:string[][]})=><section className="overflow-hidden rounded-xl border bg-white dark:border-slate-700 dark:bg-slate-900"><h2 className="border-b p-4 font-bold dark:border-slate-700">{title}</h2>{rows.length?<div className="overflow-x-auto"><table className="min-w-full text-left text-sm"><thead className="bg-slate-50 text-xs uppercase text-slate-500 dark:bg-slate-800"><tr>{headers.map(x=><th key={x} className="px-4 py-3">{x}</th>)}</tr></thead><tbody className="divide-y dark:divide-slate-800">{rows.map((r,i)=><tr key={i}>{r.map((x,j)=><td key={j} className="px-4 py-3">{x}</td>)}</tr>)}</tbody></table></div>:<p className="p-8 text-center text-sm text-slate-500">No records found.</p>}</section>;
